const f = $('🗄 Postgres: Funnel Stats').item.json;
let memo = $input.first().json;
if (memo && memo.message && memo.message.content) {
  try { memo = typeof memo.message.content==='string' ? JSON.parse(memo.message.content) : memo.message.content; } catch(e) { memo = { headline:'', bullets:[] }; }
}
const bullets = (memo.bullets||[]).map(b=>'• '+b).join('
');
const text = `📊 *DropMeds Weekly Sales OS Report*

*Headline:* ${memo.headline||'—'}

*Funnel (last 7d)*
• Sourced: ${f.total_sourced}
• Qualified: ${f.total_qualified}
• Emails sent: ${f.emails_sent}
• Replies: ${f.replies} (${f.reply_rate_pct}%)
• Hot replies: ${f.hot_replies}
• Negative: ${f.negative_replies}
• Unsubscribes: ${f.unsubscribes}

*Decisions for next 7 days:*
${bullets}`;
return [{ json: { ...f, memo, slack_text: text, total_sourced: f.total_sourced, total_qualified: f.total_qualified, emails_sent: f.emails_sent, replies: f.replies, meetings_booked: f.hot_replies, campaign_id: ($('When Executed by Parent').item ? $('When Executed by Parent').item.json.campaign_id : 'scheduled') } }];
